You have access to the following tools:
{"name":"browser_fetch","description":"Fetch URL with headless browser. Modes: text (default), html, screenshot, markdown. Use waitFor for dynamic content.","parameters":{"type":"object","properties":{"url":{"type":"string"},"mode":{"type":"string","enum":["text","html","screenshot","markdown"]},"waitFor":{"type":"string","description":"CSS selector to wait for"},"fullPage":{"type":"boolean"},"viewport":{"type":"object","description":"Override default viewport size. Defaults to 1920x1080.","properties":{"width":{"type":"number"},"height":{"type":"number"}}}},"required":["url"]}}
{"name":"browser_evaluate","description":"Execute JavaScript in page context","parameters":{"type":"object","properties":{"url":{"type":"string"},"script":{"type":"string","description":"JS code (must return value)"},"waitFor":{"type":"string"}},"required":["url","script"]}}
{"name":"browser_pdf","description":"Generate PDF of page","parameters":{"type":"object","properties":{"url":{"type":"string"},"format":{"type":"string","enum":["A4","Letter","Legal","Tabloid"]},"landscape":{"type":"boolean"},"printBackground":{"type":"boolean"}},"required":["url"]}}
{"name":"browser_session_create","description":"Create a persistent browser session. Returns a sessionId in the response text. Use this sessionId in all subsequent browser_session_* calls (goto, content, click, fill, evaluate, scroll, metadata, close). Example: call this first, then use browser_session_goto with the returned sessionId.","parameters":{"type":"object","properties":{"viewport":{"type":"object","description":"Override default viewport size","properties":{"width":{"type":"number"},"height":{"type":"number"}}},"userAgent":{"type":"string","description":"Custom user agent string"}}}}
{"name":"browser_session_list","description":"List all active browser sessions","parameters":{"type":"object","properties":{}}}
{"name":"browser_session_close","description":"Close a specific browser session","parameters":{"type":"object","properties":{"sessionId":{"type":"string","description":"Session ID to close"}},"required":["sessionId"]}}
{"name":"browser_session_goto","description":"Navigate to a URL. Requires sessionId from browser_session_create. Returns confirmation with the URL navigated to. Has built-in retry with exponential backoff for flaky loads.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"},"url":{"type":"string"},"waitFor":{"type":"string","description":"CSS selector to wait for after navigation"},"timeout":{"type":"number","description":"Navigation timeout in ms (default 30000)"},"retries":{"type":"number","description":"Max retries on failure (default 2)"}},"required":["sessionId","url"]}}
{"name":"browser_session_content","description":"Get page content. mode 'text' extracts readable text, 'screenshot' returns base64 image, 'html' returns raw HTML, 'markdown' returns markdown-formatted content. Requires sessionId from browser_session_create.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"},"mode":{"type":"string","enum":["text","html","markdown","screenshot"]}},"required":["sessionId"]}}
{"name":"browser_session_click","description":"Click an element by CSS selector. Returns page content after the click (use mode to get screenshot or text). Requires sessionId from browser_session_create. Has built-in retry for flaky elements.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"},"selector":{"type":"string"},"waitAfter":{"type":"number"},"mode":{"type":"string","enum":["text","html","screenshot"]},"retries":{"type":"number","description":"Max retries on failure (default 2)"}},"required":["sessionId","selector"]}}
{"name":"browser_session_fill","description":"Fill form fields and optionally submit. Each field has a CSS selector and value. If submit selector is provided, clicks it after filling. Returns page content. Requires sessionId from browser_session_create. Has built-in retry for flaky forms.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"},"fields":{"type":"array","items":{"type":"object","properties":{"selector":{"type":"string"},"value":{"type":"string"}}}},"submit":{"type":"string"},"waitAfter":{"type":"number"},"mode":{"type":"string","enum":["text","html","screenshot"]},"retries":{"type":"number","description":"Max retries on failure (default 2)"}},"required":["sessionId","fields"]}}
{"name":"browser_session_evaluate","description":"Execute JavaScript in the page context. Script must return a value (string, number, or JSON-serializable object). Requires sessionId from browser_session_create.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"},"script":{"type":"string"},"waitFor":{"type":"string"}},"required":["sessionId","script"]}}
{"name":"browser_session_scroll","description":"Scroll the page. direction 'down' or 'up', amount in pixels (default 500). Requires sessionId from browser_session_create.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"},"direction":{"type":"string","enum":["up","down"]},"amount":{"type":"number","description":"Pixels to scroll (default 500)"}},"required":["sessionId"]}}
{"name":"browser_session_type","description":"Type text into a focused element or simulate keystrokes. Sends key events character-by-character, which triggers input validators and dynamic form handlers better than direct value setting. Use for CAPTCHAs, autocomplete, or sites that validate on key events.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"},"selector":{"type":"string","description":"CSS selector to focus before typing (optional - if omitted, types into currently focused element)"},"text":{"type":"string","description":"Text to type"},"delay":{"type":"number","description":"Delay between keystrokes in ms (default 0, use 50-100 for slow sites)"},"keystrokes":{"type":"array","description":"Special key presses: Enter, Tab, Escape, ArrowUp, ArrowDown, ArrowLeft, ArrowRight, Backspace, Delete, Home, End, PageUp, PageDown","items":{"type":"string"}}},"required":["sessionId"]}}
{"name":"browser_session_inspect","description":"Get detailed info about an element: tag, attributes, text content, position, visibility, and an optional sub-screenshot cropped to the element. Useful for debugging selectors and understanding element state.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"},"selector":{"type":"string"},"screenshot":{"type":"boolean","description":"Include sub-screenshot of element (default false)"}},"required":["sessionId","selector"]}}
{"name":"browser_session_console","description":"Get console messages and errors captured from the page JavaScript since last call or session start. Buffers messages per session. Returns all accumulated messages and clears the buffer.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"}},"required":["sessionId"]}}
{"name":"browser_session_wait","description":"Enhanced waiting with multiple options: wait for CSS selector (with OR logic for multiple), text content in page, URL pattern matching, or custom condition via JS. More flexible than waitFor in goto.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"},"selectors":{"type":"array","description":"CSS selectors - waits for ANY to appear (OR logic)"},"text":{"type":"string","description":"Text to wait for in page content"},"urlPattern":{"type":"string","description":"Regex pattern to match against current URL"},"condition":{"type":"string","description":"JS expression that must evaluate to truthy"},"timeout":{"type":"number","description":"Max wait in ms (default 15000)"}},"required":["sessionId"]}}
{"name":"browser_session_metadata","description":"Get current page metadata: URL, title, and viewport dimensions. Useful to verify navigation succeeded. Requires sessionId from browser_session_create.","parameters":{"type":"object","properties":{"sessionId":{"type":"string"}},"required":["sessionId"]}}
{"name":"list_codebases","description":"List all indexed codebases with status and file counts","parameters":{"type":"object","properties":{}}}
{"name":"list_spaces","description":"List available spaces (configured project roots) for indexing codebases. Use this to find space names before calling index_codebase.","parameters":{"type":"object","properties":{}}}
{"name":"search_codebase","description":"[RECOMMENDED] Primary focused search tool for a single codebase. Very fast. Combines semantic (meaning) + keyword (exact) matching. ALWAYS use this first before falling back to search_all_codebases. Use strategy:keyword for fast exact name lookups, strategy:semantic for conceptual queries. Use analyze:true to get an AI-summarized response (saves tokens). Codebase name supports partial matching.","parameters":{"type":"object","properties":{"codebase":{"type":"string","description":"Codebase name (partial match supported)"},"query":{"type":"string","description":"Search query (natural language or keywords)"},"strategy":{"type":"string","enum":["hybrid","semantic","keyword"],"default":"hybrid","description":"hybrid=best overall, keyword=fast exact match, semantic=conceptual similarity"},"limit":{"type":"number","default":10},"filter":{"type":"object","properties":{"language":{"type":"string"}}},"analyze":{"type":"boolean","default":false,"description":"Use local LLM to analyze results and return structured summary with keyFindings, relevantFiles, implementationPatterns. Saves 50-90% tokens vs raw results. Recommended for exploration."},"includeRaw":{"type":"boolean","default":false,"description":"Include raw search results in addition to analysis. Use when you want both the AI summary AND original snippets for drilling down."}},"required":["codebase","query"]}}
{"name":"search_semantic","description":"Semantic (AI embedding) search - finds conceptually similar code. Best for: \"how is X implemented?\", \"find code that does Y\", pattern discovery. Slower than keyword but understands meaning, not just text. Use analyze:true for structured summary. Codebase name supports partial matching.","parameters":{"type":"object","properties":{"codebase":{"type":"string","description":"Codebase name (partial match supported)"},"query":{"type":"string","description":"Natural language query describing what you are looking for"},"limit":{"type":"number","default":10},"filter":{"type":"object","properties":{"language":{"type":"string"}}},"analyze":{"type":"boolean","default":false,"description":"Use local LLM to analyze results and return structured summary with keyFindings, relevantFiles, implementationPatterns. Saves 50-90% tokens vs raw results. Recommended for exploration."},"includeRaw":{"type":"boolean","default":false,"description":"Include raw search results in addition to analysis. Use when you want both the AI summary AND original snippets for drilling down."}},"required":["codebase","query"]}}
{"name":"search_keyword","description":"[FASTEST] Indexed keyword search. Best for: exact function names, class names, variable names, imports. Searches file paths AND content. Much faster than grep_codebase (<100ms vs 1-3s). Use this INSTEAD of grep_codebase when searching for specific identifiers. Codebase name supports partial matching.","parameters":{"type":"object","properties":{"codebase":{"type":"string","description":"Codebase name (partial match supported)"},"query":{"type":"string","description":"Keywords to search (function names, class names, etc.)"},"limit":{"type":"number","default":20},"searchContent":{"type":"boolean","default":true,"description":"Search file content (not just paths). Slightly slower but more thorough."},"analyze":{"type":"boolean","default":false,"description":"Use local LLM to analyze results and return structured summary (reduces token cost for calling LLM)"},"includeRaw":{"type":"boolean","default":false,"description":"Include raw search results in addition to analysis (increases token usage)"}},"required":["codebase","query"]}}
{"name":"grep_codebase","description":"Live regex search using ripgrep. ALWAYS CURRENT (searches filesystem directly). Slowest single-codebase search. Use ONLY when: (1) You need complex regex patterns, (2) You need exact line numbers for editing, (3) You strongly suspect the index is stale. OTHERWISE prefer search_keyword (faster for exact names) or search_semantic (for concepts). Codebase name supports partial matching.","parameters":{"type":"object","properties":{"codebase":{"type":"string","description":"Codebase name (partial match supported)"},"pattern":{"type":"string","description":"Search pattern (regex or literal string)"},"regex":{"type":"boolean","default":true,"description":"Use regex pattern matching. Set to false for literal string search (faster)"},"limit":{"type":"number","default":50,"description":"Max total results to return"},"maxMatchesPerFile":{"type":"number","default":5,"description":"Max matches per file (-1 for unlimited, 1 for \"find files only\")"},"caseSensitive":{"type":"boolean","default":false,"description":"Case-sensitive search"},"pathPattern":{"type":"string","description":"Filter by file path glob (e.g., \"*.js\", \"src/**\")"},"noCache":{"type":"boolean","default":false,"description":"Skip cache and force fresh search"},"analyze":{"type":"boolean","default":false,"description":"Use local LLM to analyze results and return structured summary with keyFindings, relevantFiles, implementationPatterns. Saves 50-90% tokens vs raw results."},"includeRaw":{"type":"boolean","default":false,"description":"Include raw search results in addition to analysis. Use when you want both the AI summary AND original snippets for drilling down."}},"required":["codebase","pattern"]}}
{"name":"search_all_codebases","description":"[AVOID IF POSSIBLE] Slowest search method. Search across ALL indexed codebases at once. ONLY use this as a last resort when focused searches on individual codebases have failed, or for extremely broad queries like \"how is X implemented across different projects?\" Use analyze:true to get AI-summarized insights instead of raw snippets.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Search query (natural language, keywords, or grep pattern)"},"strategy":{"type":"string","enum":["hybrid","semantic","keyword","grep"],"default":"hybrid","description":"hybrid=best overall (default), keyword=fastest, semantic=conceptual, grep=slow regex (avoid unless needed)"},"limit":{"type":"number","default":20,"description":"Total result limit across all codebases"},"perCodebaseLimit":{"type":"number","default":5,"description":"Max results per codebase"},"concurrency":{"type":"number","default":10,"description":"Number of codebases to search in parallel"},"filter":{"type":"object","properties":{"language":{"type":"string"}}},"analyze":{"type":"boolean","default":false,"description":"Use local LLM to analyze results and return structured summary with keyFindings, relevantFiles, implementationPatterns. Saves 50-90% tokens vs raw results. STRONGLY RECOMMENDED for cross-codebase exploration."},"includeRaw":{"type":"boolean","default":false,"description":"Include raw search results in addition to analysis. Use when you want both the AI summary AND original snippets for drilling down."}},"required":["query"]}}
{"name":"get_file_info","description":"Get file structure (functions, classes, imports) without content. Codebase name supports partial matching.","parameters":{"type":"object","properties":{"codebase":{"type":"string","description":"Codebase name (partial match supported)"},"path":{"type":"string"}},"required":["codebase","path"]}}
{"name":"get_file","description":"Get file content with staleness check. Codebase name supports partial matching.","parameters":{"type":"object","properties":{"codebase":{"type":"string","description":"Codebase name (partial match supported)"},"path":{"type":"string"}},"required":["codebase","path"]}}
{"name":"check_codebase_status","description":"Check staleness status of a codebase (stale files, missing files). Codebase name supports partial matching.","parameters":{"type":"object","properties":{"codebase":{"type":"string","description":"Codebase name (partial match supported)"}},"required":["codebase"]}}
{"name":"check_file_stale","description":"Check if a specific file is stale (changed since indexing). Codebase name supports partial matching.","parameters":{"type":"object","properties":{"codebase":{"type":"string","description":"Codebase name (partial match supported)"},"path":{"type":"string","description":"File path relative to codebase root"}},"required":["codebase","path"]}}
{"name":"get_codebase_description","description":"Get LLM-generated project description with staleness check. Codebase name supports partial matching.","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Codebase name (partial match supported)"}},"required":["name"]}}
{"name":"get_prioritized_files","description":"Get files ordered by importance (high/medium/low priority). Codebase name supports partial matching.","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Codebase name (partial match supported)"}},"required":["name"]}}
{"name":"get_documentation","description":"Get the main orchestrator documentation (tools guide). Equivalent to read_document({name: 'orchestrator'}).","parameters":{"type":"object","properties":{}}}
{"name":"list_documents","description":"List all available documentation files in the mcp_documentation folder.","parameters":{"type":"object","properties":{}}}
{"name":"read_document","description":"Read a specific documentation file by name (without .md extension).","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Document name without extension (e.g., 'orchestrator', 'coding-philosophy')"}},"required":["name"]}}
{"name":"inspect_code","description":"Analyze existing code files iteratively. Finds bugs, explains architecture, or suggests improvements. File paths must be absolute.","parameters":{"type":"object","properties":{"files":{"type":"array","items":{"type":"string"},"description":"Absolute paths of files to inspect (e.g. 'D:\\Project\\src\\main.js')."},"prompt":{"type":"string","description":"Specific question or analysis request for these files."}},"required":["files","prompt"]}}
{"name":"query_model","description":"Query the local LLM. To include files, use absolute paths.","parameters":{"type":"object","properties":{"prompt":{"type":"string"},"files":{"type":"array","items":{"type":"string"}},"systemPrompt":{"type":"string","description":"Optional system prompt. Overrides the default assistant prompt."}},"required":["prompt"]}}
{"name":"remember","description":"Store a memory. Categories: proven, anti_patterns, hypotheses, context, observed. Use domain for project-specific memories.","parameters":{"type":"object","properties":{"text":{"type":"string","description":"Memory content"},"category":{"type":"string","description":"Category"},"domain":{"type":"string","description":"Optional project scope"}},"required":["text","category"]}}
{"name":"recall","description":"Search memories. Results show confidence: [v]=proven, ~=promising, ?=hypothesis.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Search query"},"limit":{"type":"number","description":"Max results (default: 5)"},"category":{"type":"string","description":"Filter by category"},"domain":{"type":"string","description":"Filter by project"}},"required":["query"]}}
{"name":"forget","description":"Delete a memory by ID","parameters":{"type":"object","properties":{"id":{"type":"number"}},"required":["id"]}}
{"name":"list_memories","description":"List all memories. Filter by category/domain.","parameters":{"type":"object","properties":{"category":{"type":"string"},"domain":{"type":"string"}}}}
{"name":"update_memory","description":"Update a memory by ID","parameters":{"type":"object","properties":{"id":{"type":"number"},"text":{"type":"string"},"category":{"type":"string"},"domain":{"type":"string"}},"required":["id","text"]}}
{"name":"reflect_on_session","description":"USER-INITIATED. Analyze session for quality improvements. Returns proposed changes.","parameters":{"type":"object","properties":{"sessionSummary":{"type":"string"}},"required":["sessionSummary"]}}
{"name":"apply_reflection_changes","description":"Apply changes from reflection","parameters":{"type":"object","properties":{"changes":{"type":"array","items":{"type":"object","properties":{"action":{"type":"string","enum":["create","update","reinforce","decrease"]},"id":{"type":"number","description":"Memory ID (for update/reinforce/decrease)"},"text":{"type":"string","description":"Memory text (for create/update)"},"category":{"type":"string","description":"Category (for create/update)"},"domain":{"type":"string","description":"Optional project scope"},"reason":{"type":"string","description":"Reason for the change"}},"required":["action"]}}},"required":["changes"]}}
{"name":"research_topic","description":"Research a topic via web search. Multi-phase: search, scrape, synthesize with citations.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Search query (quote terms, use site: filters)"},"engines":{"type":"array","items":{"type":"string","enum":["google","duckduckgo","bing"]}},"max_pages":{"type":"number","description":"Max pages (default: 10)"}},"required":["query"]}}
{"name":"vision_create_session","description":"Create a new image session for analysis. Returns a session_id to use with vision_analyze. The session stores the original image and accumulates analyses over time.","parameters":{"type":"object","properties":{"image_url":{"type":"string","description":"Image URL (remote or data URL). Either this or image_data is required."},"image_data":{"type":"string","description":"Base64-encoded image data. Alternative to image_url."},"image_mime_type":{"type":"string","description":"MIME type (e.g., 'image/jpeg', 'image/png'). Required if using image_data."}},"oneOf":[{"required":["image_url"]},{"required":["image_data","image_mime_type"]}]}}
{"name":"vision_analyze","description":"Analyze an image. Previous analyses are included as context, enabling ever-sharpening detail. Use 'focus' to zoom into specific regions for higher resolution analysis of that area.","parameters":{"type":"object","properties":{"session_id":{"type":"string","description":"Session ID from vision_create_session"},"query":{"type":"string","description":"What to analyze. Examples: 'Describe everything', 'What is the person wearing?', 'Read the text on the sign'"},"focus":{"type":"object","description":"Optional: Region to focus on for higher resolution analysis","properties":{"text":{"type":"string","description":"Free text focus: 'top-left corner', 'person on the left', 'the sign in the background'"},"grid":{"type":"object","description":"Grid-based focus: divide image into cols x rows, analyze specific cells","properties":{"cols":{"type":"number","description":"Number of columns (e.g., 2 for 2x2 grid)"},"rows":{"type":"number","description":"Number of rows (e.g., 2 for 2x2 grid)"},"cells":{"type":"array","items":{"type":"number"},"description":"Cell indices to analyze (0=top-left, read left-to-right, top-to-bottom)"}}},"region":{"type":"object","description":"Normalized pixel region for precise cropping","properties":{"left":{"type":"number","minimum":0,"maximum":1},"top":{"type":"number","minimum":0,"maximum":1},"right":{"type":"number","minimum":0,"maximum":1},"bottom":{"type":"number","minimum":0,"maximum":1}}},"centerCrop":{"oneOf":[{"type":"number","description":"Crop to center N% (e.g., 50 = keep center 50%)"},{"type":"object","description":"Asymmetric center crop","properties":{"widthPercent":{"type":"number"},"heightPercent":{"type":"number"}}}]}}},"include_context":{"type":"boolean","default":true,"description":"Whether to include previous analyses as context"}},"required":["session_id"]}}
{"name":"vision_close_session","description":"Close an image session and free memory. Sessions auto-expire after 30 minutes of inactivity, but this frees resources immediately.","parameters":{"type":"object","properties":{"session_id":{"type":"string","description":"Session ID to close"}},"required":["session_id"]}}
{"name":"vision_list_sessions","description":"List all active image sessions","parameters":{"type":"object","properties":{}}}
{"name":"vision_get_session","description":"Get details about a session including accumulated analyses","parameters":{"type":"object","properties":{"session_id":{"type":"string","description":"Session ID to inspect"}},"required":["session_id"]}}

To invoke a tool, you MUST output a single line with the exact following syntax, self-delimited, without any surrounding markdown formatting or text on that line:
__TOOL_CALL__({"name": "tool_name", "args": {"param1": "value"}})

After you output a tool call, the system will execute it and provide you with a new message containing the result formatted like this:
<tool_result>
  <tool_name>...</tool_name>
  <status>success|error</status>
  <output>...</output>
</tool_result>
Do not attempt to guess or hallucinate the tool's result.
